import { router, protectedProcedure, publicProcedure } from "packages/backend/src/trpc/core";
import { isAdmin, requirePermission } from "./middleware";
import { z } from "zod";
// import { TRPCError } from "@trpc/server";
import { PrismaClient } from "@prisma/client";

// const prisma = new PrismaClient();

/**
 * Utils
 */
const cleanExpiredSessions = async (prisma: PrismaClient) => {
  await prisma.session.deleteMany({
    where: {
      expiresAt: {
        lte: new Date(),
      },
    },
  })
}

export const sessionRouter = router({
  update: protectedProcedure
    .use(isAdmin)
    .input(z.object({
      id: z.string(),
      token: z.string(),
      userId: z.string(),
      role: z.string(),
      createdAt: z.date(),
      expiresAt: z.date(),      
    }))
    .mutation(async ({ ctx, input }) => {
      return ctx.prisma.session.update({
        where: { id: input.id },
        data: {
          // token: input.token,
          ...(input.expiresAt ? { expiresAt: input.expiresAt } : {}),
        },
      });
    }),

  getSession: publicProcedure
    .query(async ({ ctx }) => {
      try {
        return await ctx.prisma.session.findMany();
      } catch (error) {
        console.log('Error fetching sessions:', error);
      }
    })

  
});